import requests
import os


class Tools:
    @staticmethod
    def run(query: str, model: str = "gemini-1.5-pro-latest") -> dict:
        """
        Send academic/research query to Google Gemini.
        Strong on math, figures, recent papers, multimodal reasoning.
        """
        api_key = os.environ.get("GEMINI_API_KEY")
        if not api_key:
            return {"error": "GEMINI_API_KEY not found"}

        url = f"https://generativelanguage.googleapis.com/v1beta/models/{model}:generateContent"

        params = {"key": api_key}

        payload = {
            "contents": [
                {
                    "parts": [
                        {
                            "text": f"You are an expert academic researcher. Provide detailed, accurate answers with references and reasoning.\n\n{query}"
                        }
                    ]
                }
            ],
            "generationConfig": {"temperature": 0.3, "maxOutputTokens": 2048},
        }

        try:
            r = requests.post(url, params=params, json=payload, timeout=60)
            r.raise_for_status()
            return r.json()
        except Exception as e:
            return {"error": str(e)}
